 {"id":"bd-1n5t.2","title":"FocusManager Core Implementation","description":"Central focus manager that coordinates widget focus state.

## Requirements
- Single source of truth for current focus
- Focus history stack for back navigation
- Focus groups for tabbing behavior
- Integration with Model trait

## Proposed API

```rust
/// Central focus coordinator
pub struct FocusManager {
    graph: FocusGraph,
    current_focus: Option<FocusId>,
    focus_history: Vec<FocusId>,
    trap_stack: Vec<FocusTrap>,
    groups: HashMap<u32, FocusGroup>,
}

/// Focus group for Tab navigation boundaries
pub struct FocusGroup {
    pub id: u32,
    pub members: Vec<FocusId>,
    pub wrap: bool,          // Wrap at group boundaries
    pub exit_key: Option<KeyCode>,  // Key to exit group
}

/// Active focus trap (for modals)
pub struct FocusTrap {
    pub group_id: u32,
    pub return_focus: FocusId,
}

impl FocusManager {
    pub fn new() -> Self;

    // --- Focus Control ---

    /// Set focus to widget, returns previous focus
    pub fn focus(&mut self, id: FocusId) -> Option<FocusId>;

    /// Remove focus from current widget
    pub fn blur(&mut self) -> Option<FocusId>;

    /// Get currently focused widget
    pub fn current(&self) -> Option<FocusId>;

    // --- Navigation ---

    /// Move focus in direction
    pub fn navigate(&mut self, dir: NavDirection) -> bool;

    /// Move to next in tab order
    pub fn focus_next(&mut self) -> bool;

    /// Move to previous in tab order
    pub fn focus_prev(&mut self) -> bool;

    /// Focus first focusable widget
    pub fn focus_first(&mut self) -> bool;

    /// Focus last focusable widget
    pub fn focus_last(&mut self) -> bool;

    // --- History ---

    /// Go back to previous focus
    pub fn focus_back(&mut self) -> bool;

    /// Clear focus history
    pub fn clear_history(&mut self);

    // --- Trapping ---

    /// Push focus trap (for modals)
    pub fn push_trap(&mut self, group_id: u32);

    /// Pop focus trap, restore previous focus
    pub fn pop_trap(&mut self) -> bool;

    /// Check if focus is currently trapped
    pub fn is_trapped(&self) -> bool;

    // --- Groups ---

    /// Create focus group
    pub fn create_group(&mut self, id: u32, members: Vec<FocusId>);

    /// Add widget to group
    pub fn add_to_group(&mut self, group_id: u32, widget_id: FocusId);

    // --- Events ---

    /// Generate focus change event
    pub fn focus_event(&self) -> Option<FocusEvent>;
}

#[derive(Clone, Debug)]
pub enum FocusEvent {
    FocusGained { id: FocusId },
    FocusLost { id: FocusId },
    FocusMoved { from: FocusId, to: FocusId },
}
```

## Runtime Integration

```rust
// In Program/Runtime
impl<M: Model> Program<M> {
    fn handle_focus_key(&mut self, key: KeyEvent) -> Option<Cmd<M::Message>> {
        match key.code {
            KeyCode::Tab if key.modifiers.is_empty() => {
                self.focus_manager.focus_next();
                Some(Cmd::none())
            }
            KeyCode::Tab if key.modifiers.contains(Modifiers::SHIFT) => {
                self.focus_manager.focus_prev();
                Some(Cmd::none())
            }
            KeyCode::Esc if self.focus_manager.is_trapped() => {
                self.focus_manager.pop_trap();
                Some(Cmd::none())
            }
            _ => None
        }
    }
}
```

